//! 缁熶竴宸ュ叿鍔犺浇鍣ㄦā鍧?//!//! # 姒傝堪//!//! `ToolLoader` 鎻愪緵缁熶竴鐨勬帴鍙ｆ潵鍔犺浇鍜岀鐞嗘潵鑷笉鍚屾潵婧愮殑宸ュ叿銆?//! 瀹冪畝鍖栦簡宸ュ叿娉ㄥ唽娴佺▼锛屾敮鎸侀摼寮忚皟鐢ㄥ拰鏉′欢杩囨护銆?//!//! # 鏀寔鐨勫伐鍏锋潵婧?//!//! - **Mcp**: 浠?MCP锛圡odel Context Protocol锛夋湇鍔″櫒鍔犺浇鐨勫伐鍏?//! - **A2A**: 浠?A2A锛圓gent-to-Agent锛夊崗璁姞杞界殑宸ュ叿//! - **Custom**: 鐢ㄦ埛鑷畾涔夊伐鍏凤紙閫氳繃 `register()` 鏂规硶鎵嬪姩娉ㄥ唽锛?//!//! # 鍏充簬鍐呯疆宸ュ叿鍜?Skills//!//! `agentkit-runtime` 鏈韩涓嶆彁渚涘唴缃伐鍏锋垨 Skills 鍔犺浇鍔熻兘銆?//! 濡傛灉闇€瑕佷娇鐢ㄥ唴缃伐鍏凤紙濡?shell銆乫ile銆乭ttp 绛夛級鎴?Skills锛?//! 璇蜂娇鐢?`agentkit` crate 涓殑宸ュ叿鍔犺浇鍣紝鎴栨墜鍔ㄦ敞鍐屽疄鐜?`Tool` trait 鐨勭被鍨嬨€?//!//! # 浣跨敤绀轰緥//!//! ## 鍩烘湰浣跨敤//!//! ```rust,no_run//! use agentkit::runtime::loader::ToolLoader;//! use agentkit::runtime::ToolWrapper;//!//! # async fn example() -> Result<(), Box<dyn std::error::Error>> {//! // 鎵嬪姩娉ㄥ唽鑷畾涔夊伐鍏?//! let loader = ToolLoader::new()//!     .register(MyCustomTool::new());//!//! let registry = loader.build();//! # Ok(())//! # }//! ```//!//! ## 浣跨敤杩囨护鍣?//!//! ```rust,no_run//! use agentkit::runtime::loader::ToolLoader;//!//! # async fn example() -> Result<(), Box<dyn std::error::Error>> {//! // 鍙姞杞界壒瀹氬伐鍏?//! let loader = ToolLoader::new()//!     .include("shell")      // 鍖呭惈 shell//!     .include("file")       // 鍖呭惈 file//!     .exclude("dangerous")  // 鎺掗櫎 dangerous//!     .register(MyCustomTool::new());//!//! let registry = loader.build();//! # Ok(())//! # }//! ```//!//! ## 浣跨敤 MCP 宸ュ叿//!//! ```rust,no_run//! # #[cfg(feature = "mcp")]//! use agentkit::runtime::loader::ToolLoader;//!//! # #[cfg(feature = "mcp")]//! # async fn example(client: rmcp::client::Client) -> Result<(), Box<dyn std::error::Error>> {//! let loader = ToolLoader::new()//!     .load_mcp_tools(client)//!     .await?;//!//! let registry = loader.build();//! # Ok(())//! # }//! ```//!//! ## 鑾峰彇鍔犺浇缁熻//!//! ```rust,no_run//! use agentkit::runtime::loader::ToolLoader;//!//! # async fn example() -> Result<(), Box<dyn std::error::Error>> {//! let (registry, stats) = ToolLoader::new()//!     .register(MyCustomTool::new())//!     .build_with_stats();//!//! stats.print();//! # Ok(())//! # }//! ```//!//! ## 渚挎嵎鍑芥暟//!//! ```rust,no_run//! use agentkit::runtime::loader::load_tools;//!//! # async fn example() -> Result<(), Box<dyn std::error::Error>> {//! // 涓€閿姞杞?MCP 宸ュ叿//! # #[cfg(feature = "mcp")]//! let (registry, stats) = load_tools(Some(client)).await?;//!//! stats.print();//! # Ok(())//! # }//! ```//!//! # 鍏充簬鍐呯疆宸ュ叿//!//! `agentkit-runtime` 涓嶆彁渚涘唴缃伐鍏枫€傚鏋滈渶瑕佷娇鐢ㄥ唴缃伐鍏凤紝鍙互锛?//!//! 1. 浣跨敤 `agentkit` crate 涓殑宸ュ叿绫诲瀷鎵嬪姩娉ㄥ唽锛?//!//! ```rust,no_run//! use agentkit::runtime::loader::ToolLoader;//! use agentkit::tools::{ShellTool, FileReadTool};//!//! # async fn example() -> Result<(), Box<dyn std::error::Error>> {//! let loader = ToolLoader::new()//!     .register(ShellTool::new())//!     .register(FileReadTool::new());//!//! let registry = loader.build();//! # Ok(())//! # }//! ```//!//! 2. 鎴栬€呭疄鐜拌嚜宸辩殑宸ュ叿绫诲瀷骞舵敞鍐屻€?use std::path::Path;use tracing::{debug, info};use crate::runtime::tool_registry::{ToolRegistry, ToolSource};/// 宸ュ叿鍔犺浇鍣ㄦ瀯寤哄櫒////// 鎻愪緵閾惧紡 API 鏉ュ姞杞藉拰閰嶇疆宸ュ叿銆?////// # 绀轰緥////// ```rust,no_run/// use agentkit::runtime::loader::ToolLoader;////// # async fn example() -> Result<(), Box<dyn std::error::Error>> {/// let loader = ToolLoader::new()///     .with_auto_namespace()  // 鍚敤鑷姩鍛藉悕绌洪棿///     .exclude("dangerous")   // 鎺掗櫎鍗遍櫓宸ュ叿///     .load_builtin_tools()///     .load_skills_from_dir("skills")///     .await?;////// let registry = loader.build();/// # Ok(())/// # }/// ```pub struct ToolLoader {    /// 宸ュ叿娉ㄥ唽琛?    registry: ToolRegistry,    /// 鏄惁鍚敤鑷姩鍛藉悕绌洪棿    auto_namespace: bool,    /// 宸ュ叿鍚嶇О鍖呭惈杩囨护妯″紡    include_patterns: Vec<String>,    /// 宸ュ叿鍚嶇О鎺掗櫎杩囨护妯″紡    exclude_patterns: Vec<String>,}impl Default for ToolLoader {    fn default() -> Self {        Self::new()    }}impl ToolLoader {    /// 鍒涘缓鏂扮殑宸ュ叿鍔犺浇鍣?    ///    /// # 绀轰緥    ///    /// ```rust    /// use agentkit::runtime::loader::ToolLoader;    ///    /// let loader = ToolLoader::new();    /// ```    pub fn new() -> Self {        Self {            registry: ToolRegistry::new(),            auto_namespace: false,            include_patterns: vec![],            exclude_patterns: vec![],        }    }    /// 鍚敤鑷姩鍛藉悕绌洪棿锛堟寜鏉ユ簮锛?    ///    /// 鍚敤鍚庯紝宸ュ叿浼氭牴鎹潵婧愯嚜鍔ㄦ坊鍔犲懡鍚嶇┖闂村墠缂€锛?    /// 渚嬪锛歚builtin::shell`銆乣skill::weather`銆?    ///    /// # 绀轰緥    ///    /// ```rust,no_run    /// use agentkit::runtime::loader::ToolLoader;    ///    /// # async fn example() -> Result<(), Box<dyn std::error::Error>> {    /// let loader = ToolLoader::new()    ///     .with_auto_namespace()    ///     .load_builtin_tools()    ///     .await?;    ///    /// let registry = loader.build();    /// // 宸ュ叿鍚嶇О浼氭槸 builtin::shell 鑰屼笉鏄?shell    /// # Ok(())    /// # }    /// ```    pub fn with_auto_namespace(mut self) -> Self {        self.auto_namespace = true;        self    }    /// 娣诲姞宸ュ叿鍚嶇О鍖呭惈杩囨护    ///    /// 鍙湁鍚嶇О鍖呭惈鎸囧畾妯″紡鐨勫伐鍏锋墠浼氳鍔犺浇銆?    ///    /// # 绀轰緥    ///    /// ```rust    /// use agentkit::runtime::loader::ToolLoader;    ///    /// let loader = ToolLoader::new()    ///     .include("shell")   // 鍙姞杞藉寘鍚?shell 鐨勫伐鍏?    ///     .include("file");   // 鎴栧寘鍚?file 鐨勫伐鍏?    /// ```    pub fn include(mut self, pattern: impl Into<String>) -> Self {        self.include_patterns.push(pattern.into());        self    }    /// 娣诲姞宸ュ叿鍚嶇О鎺掗櫎杩囨护    ///    /// 鍚嶇О鍖呭惈鎸囧畾妯″紡鐨勫伐鍏蜂細琚帓闄ゃ€?    ///    /// # 绀轰緥    ///    /// ```rust    /// use agentkit::runtime::loader::ToolLoader;    ///    /// let loader = ToolLoader::new()    ///     .exclude("dangerous")  // 鎺掗櫎鍗遍櫓宸ュ叿    ///     .exclude("debug");     // 鎺掗櫎璋冭瘯宸ュ叿    /// ```    pub fn exclude(mut self, pattern: impl Into<String>) -> Self {        self.exclude_patterns.push(pattern.into());        self    }    /// 妫€鏌ュ伐鍏峰悕绉版槸鍚﹀簲璇ヨ鍖呭惈    fn should_include(&self, name: &str) -> bool {        // 濡傛灉鏈夋帓闄ゆā寮忓尮閰嶏紝鍒欐帓闄?        if self.exclude_patterns.iter().any(|p| name.contains(p)) {            return false;        }        // 濡傛灉鏈夊寘鍚ā寮忥紝蹇呴』鍖归厤鍏朵腑涓€涓?        if !self.include_patterns.is_empty() {            return self.include_patterns.iter().any(|p| name.contains(p));        }        true    }    /// 娉ㄥ唽鍗曚釜宸ュ叿    ///    /// # 绀轰緥    ///    /// ```rust    /// use agentkit::runtime::loader::ToolLoader;    /// use agentkit::tools::ShellTool;    ///    /// let loader = ToolLoader::new()    ///     .register(ShellTool::new());    /// ```    pub fn register<T: agentkit_core::tool::Tool + 'static>(mut self, tool: T) -> Self {        let name = tool.name().to_string();        if self.should_include(&name) {            debug!(tool.name = %name, "loader.register.tool");            self.registry = self.registry.register(tool);        } else {            debug!(tool.name = %name, "loader.skip.tool");        }        self    }    /// 娉ㄥ唽甯︽潵婧愮殑宸ュ叿    ///    /// # 绀轰緥    ///    /// ```rust    /// use agentkit::runtime::{loader::ToolLoader, ToolSource};    /// use agentkit::tools::ShellTool;    ///    /// let loader = ToolLoader::new()    ///     .register_with_source(ShellTool::new(), ToolSource::BuiltIn);    /// ```    pub fn register_with_source<T: agentkit_core::tool::Tool + 'static>(        mut self,        tool: T,        source: ToolSource,    ) -> Self {        let name = tool.name().to_string();        if self.should_include(&name) {            debug!(tool.name = %name, tool.source = ?source, "loader.register.tool");            self.registry = self.registry.register_with_source(tool, source);        }        self    }    /// 鍚堝苟鍙︿竴涓敞鍐岃〃    ///    /// # 绀轰緥    ///    /// ```rust    /// use agentkit::runtime::{loader::ToolLoader, ToolRegistry};    ///    /// let loader1 = ToolLoader::new();    /// let loader2 = ToolLoader::new()    ///     .merge(loader1.build());    /// ```    pub fn merge(mut self, other: ToolRegistry) -> Self {        self.registry = self.registry.merge(other);        self    }    /// 鍔犺浇鍐呯疆宸ュ叿    ///    /// 鍐呯疆宸ュ叿鍖呮嫭锛?    /// - `shell`: 鎵ц绯荤粺鍛戒护    /// - `cmd_exec`: 鍙楅檺鍛戒护鎵ц锛堜粎 curl锛?    /// - `git`: Git 鎿嶄綔    /// - `file_read`, `file_write`, `file_edit`: 鏂囦欢鎿嶄綔    /// - `http_request`, `web_fetch`: 缃戠粶璇锋眰    /// - `browse`, `browser_open`: 娴忚鍣ㄦ搷浣?    /// - `memory_store`, `memory_recall`: 璁板繂瀛樺偍    ///    /// # Feature 鏍囧織    ///    /// 闇€瑕佸惎鐢?`skills` feature銆?    ///    /// # 绀轰緥    ///    /// ```rust,no_run    /// use agentkit::runtime::loader::ToolLoader;    ///    /// # async fn example() -> Result<(), Box<dyn std::error::Error>> {    /// let loader = ToolLoader::new()    ///     .load_builtin_tools();    ///    /// let registry = loader.build();    /// # Ok(())    /// # }    /// ```    #[cfg(feature = "skills")]    pub fn load_builtin_tools(mut self) -> Self {        use crate::tools::{            BrowseTool, BrowserOpenTool, CmdExecTool, FileEditTool, FileReadTool, FileWriteTool,            GitTool, HttpRequestTool, MemoryRecallTool, MemoryStoreTool, ShellTool, WebFetchTool,        };        info!("loader.builtin_tools.start");        // 鐩存帴娉ㄥ唽鍏蜂綋宸ュ叿瀹炰緥        if self.should_include("shell") {            self.registry = self                .registry                .register_with_source(ShellTool::new(), ToolSource::BuiltIn);        }        if self.should_include("cmd_exec") {            self.registry = self                .registry                .register_with_source(CmdExecTool::new(), ToolSource::BuiltIn);        }        if self.should_include("git") {            self.registry = self                .registry                .register_with_source(GitTool::new(), ToolSource::BuiltIn);        }        if self.should_include("file_read") {            self.registry = self                .registry                .register_with_source(FileReadTool::new(), ToolSource::BuiltIn);        }        if self.should_include("file_write") {            self.registry = self                .registry                .register_with_source(FileWriteTool::new(), ToolSource::BuiltIn);        }        if self.should_include("file_edit") {            self.registry = self                .registry                .register_with_source(FileEditTool::new(), ToolSource::BuiltIn);        }        if self.should_include("http_request") {            self.registry = self                .registry                .register_with_source(HttpRequestTool::new(), ToolSource::BuiltIn);        }        if self.should_include("web_fetch") {            self.registry = self                .registry                .register_with_source(WebFetchTool::new(), ToolSource::BuiltIn);        }        if self.should_include("browse") {            self.registry = self                .registry                .register_with_source(BrowseTool::new(), ToolSource::BuiltIn);        }        if self.should_include("browser_open") {            self.registry = self                .registry                .register_with_source(BrowserOpenTool::new(), ToolSource::BuiltIn);        }        if self.should_include("memory_store") {            self.registry = self                .registry                .register_with_source(MemoryStoreTool::new(), ToolSource::BuiltIn);        }        if self.should_include("memory_recall") {            self.registry = self                .registry                .register_with_source(MemoryRecallTool::new(), ToolSource::BuiltIn);        }        info!(count = 12, "loader.builtin_tools.done");        self    }    /// 浠庣洰褰曞姞杞?Skills    ///    /// Skills 浼氳杞崲涓哄伐鍏峰苟娉ㄥ唽锛屾潵婧愭爣璁颁负 `ToolSource::Skill`銆?    ///    /// # 鍙傛暟    ///    /// - `dir`: Skills 鐩綍璺緞    ///    /// # Feature 鏍囧織    ///    /// 闇€瑕佸惎鐢?`skills` feature銆?    ///    /// # 绀轰緥    ///    /// ```rust,no_run    /// use agentkit::runtime::loader::ToolLoader;    ///    /// # async fn example() -> Result<(), Box<dyn std::error::Error>> {    /// let loader = ToolLoader::new()    ///     .load_skills_from_dir("skills")    ///     .await?;    ///    /// let registry = loader.build();    /// # Ok(())    /// # }    /// ```    pub async fn load_skills_from_dir(        mut self,        dir: impl AsRef<Path>,    ) -> Result<Self, Box<dyn std::error::Error + Send + Sync>> {        let dir = dir.as_ref();        info!(skills.dir = %dir.display(), "loader.skills.start");        // 浣跨敤 agentkit 鐨?skills 鍔犺浇鍣?        #[cfg(feature = "skills")]        {            use crate::skills::{SkillLoader, SkillExecutor};                        let mut skill_loader = SkillLoader::new(dir);            let skills = skill_loader.load_from_dir().await?;            let skill_tools = skill_loader.to_tool_descriptions();            let count = skill_tools.len();            for tool in skill_tools {                let name: String = tool.get("function").and_then(|f| f.get("name")).and_then(|n| n.as_str()).unwrap_or("unknown").to_string();                if self.should_include(&name) {                    self.registry = self.registry.register_arc(tool);                    debug!(tool.name = %name, "loader.skills.registered");                }            }            info!(count, "loader.skills.done");        }        #[cfg(not(feature = "skills"))]        {            info!("skills feature not enabled, skipping skills loading");        }        Ok(self)    }    /// 浠?MCP 鏈嶅姟鍣ㄥ姞杞藉伐鍏?    ///    /// 杩炴帴鍒?MCP锛圡odel Context Protocol锛夋湇鍔″櫒骞跺姞杞藉彲鐢ㄥ伐鍏枫€?    ///    /// # 鍙傛暟    ///    /// - `client`: MCP 瀹㈡埛绔?    ///    /// # Feature 鏍囧織        // TODO: Skills 集成待实现 -     ///        // TODO: Skills 集成待实现 -     /// 闇€瑕佸惎鐢?`mcp` feature銆?    ///        // TODO: Skills 集成待实现 -     /// # 绀轰緥        // TODO: Skills 集成待实现 -     ///        // TODO: Skills 集成待实现 -     /// ```rust,no_run        // TODO: Skills 集成待实现 -     /// # #[cfg(feature = "mcp")]        // TODO: Skills 集成待实现 -     /// use agentkit::runtime::loader::ToolLoader;        // TODO: Skills 集成待实现 -     /// # #[cfg(feature = "mcp")]        // TODO: Skills 集成待实现 -     /// use rmcp::client::Client;        // TODO: Skills 集成待实现 -     ///        // TODO: Skills 集成待实现 -     /// # #[cfg(feature = "mcp")]        // TODO: Skills 集成待实现 -     /// # async fn example(client: Client) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {        // TODO: Skills 集成待实现 -     /// let loader = ToolLoader::new()        // TODO: Skills 集成待实现 -     ///     .load_mcp_tools(client)        // TODO: Skills 集成待实现 -     ///     .await?;        // TODO: Skills 集成待实现 -     ///        // TODO: Skills 集成待实现 -     /// let registry = loader.build();        // TODO: Skills 集成待实现 -     /// # Ok(())        // TODO: Skills 集成待实现 -     /// # }        // TODO: Skills 集成待实现 -     /// ```    #[cfg(feature = "mcp")]    pub async fn load_mcp_tools(        mut self,        client: crate::mcp::McpClient,    ) -> Result<Self, Box<dyn std::error::Error + Send + Sync>> {        use crate::mcp::McpTool;        info!("loader.mcp.start");        let tools = client.list_tools().await?;        let mut count = 0;        for mcp_tool in tools {            let name = mcp_tool.name.clone();            if self.should_include(&name) {                let adapter = McpTool::new(client.clone(), mcp_tool);                self.registry = self.registry.register_with_source(adapter, ToolSource::Mcp);                count += 1;                debug!(tool.name = %name, "loader.mcp.registered");            }        }        info!(count, "loader.mcp.done");        Ok(self)    }    /// 浠?A2A 浠ｇ悊鍔犺浇宸ュ叿    ///    /// 浠?A2A锛圓gent-to-Agent锛夊崗璁姞杞借繙绋嬩唬鐞嗙殑宸ュ叿銆?    ///    /// # 鍙傛暟    ///    /// - `agent_card`: A2A 浠ｇ悊鍗＄墖    /// - `transport`: A2A 浼犺緭灞?    ///    /// # Feature 鏍囧織    ///    /// 闇€瑕佸惎鐢?`a2a` feature銆?    ///    /// 娉ㄦ剰锛氭鏂规硶鏆傛椂鏈疄鐜帮紝鍥犱负 ra2a 搴撶殑 API 涓庨鏈熶笉鍚屻€?    /// 璇风洿鎺ュ湪绀轰緥涓垱寤?A2AToolAdapter銆?    ///    /// # 绀轰緥    ///    /// ```rust,no_run    /// use agentkit::a2a::A2AToolAdapter;    /// use ra2a::client::Client;    ///    /// # async fn example() -> Result<(), Box<dyn std::error::Error>> {    /// // 鐩存帴鍒涘缓 A2A 宸ュ叿    /// let client = Client::from_url("http://localhost:8080")?;    /// let tool = A2AToolAdapter::new(    ///     "remote_agent".to_string(),    ///     "杩滅▼ A2A Agent".to_string(),    ///     serde_json::json!({    ///         "type": "object",    ///         "properties": {    ///             "message": {"type": "string"}    ///         },    ///         "required": ["message"]    ///     }),    ///     client,    /// );    /// # Ok(())    /// # }    /// ```    #[cfg(feature = "a2a")]    pub async fn load_a2a_tools(        self,        _agent_card: ra2a::types::AgentCard,    ) -> Result<Self, Box<dyn std::error::Error + Send + Sync>> {        // 鏆傛椂鏈疄鐜?        Err("load_a2a_tools is not implemented yet. Please create A2AToolAdapter directly.".into())    }    /// 鏋勫缓鏈€缁堢殑 ToolRegistry    ///    /// # 绀轰緥    ///    /// ```rust,no_run    /// use agentkit::runtime::loader::ToolLoader;    ///    /// # async fn example() -> Result<(), Box<dyn std::error::Error>> {    /// let registry = ToolLoader::new()    ///     .load_builtin_tools()    ///     .build();    /// # Ok(())    /// # }    /// ```    pub fn build(self) -> ToolRegistry {        info!(            total_tools = self.registry.len(),            enabled_tools = self.registry.enabled_len(),            "loader.build"        );        self.registry    }    /// 鏋勫缓骞惰幏鍙?ToolRegistry 鍜岀粺璁′俊鎭?    ///    /// # 杩斿洖鍊?    ///    /// 杩斿洖 `(ToolRegistry, ToolLoadStats)` 鍏冪粍銆?    ///    /// # 绀轰緥    ///    /// ```rust,no_run    /// use agentkit::runtime::loader::ToolLoader;    ///    /// # async fn example() -> Result<(), Box<dyn std::error::Error>> {    /// let (registry, stats) = ToolLoader::new()    ///     .load_builtin_tools()    ///     .build_with_stats();    ///    /// stats.print();    /// # Ok(())    /// # }    /// ```    pub fn build_with_stats(self) -> (ToolRegistry, ToolLoadStats) {        let total = self.registry.len();        let enabled = self.registry.enabled_len();        let stats = ToolLoadStats {            total,            enabled,            builtin: self.registry.filter_by_source(ToolSource::BuiltIn).len(),            skill: self.registry.filter_by_source(ToolSource::Skill).len(),            mcp: self.registry.filter_by_source(ToolSource::Mcp).len(),            a2a: self.registry.filter_by_source(ToolSource::A2A).len(),            custom: self.registry.filter_by_source(ToolSource::Custom).len(),        };        info!(            total = stats.total,            enabled = stats.enabled,            builtin = stats.builtin,            skill = stats.skill,            mcp = stats.mcp,            a2a = stats.a2a,            custom = stats.custom,            "loader.build_with_stats"        );        (self.registry, stats)    }}/// 宸ュ叿鍔犺浇缁熻////// 鍖呭惈宸ュ叿鍔犺浇鐨勮缁嗕俊鎭€?////// # 瀛楁璇存槑////// - `total`: 鎬诲伐鍏锋暟/// - `enabled`: 鍚敤鐨勫伐鍏锋暟/// - `builtin`: 鍐呯疆宸ュ叿鏁?/// - `skill`: Skill 宸ュ叿鏁?/// - `mcp`: MCP 宸ュ叿鏁?/// - `a2a`: A2A 宸ュ叿鏁?/// - `custom`: 鑷畾涔夊伐鍏锋暟////// # 绀轰緥////// ```rust/// use agentkit::runtime::loader::ToolLoadStats;////// let stats = ToolLoadStats {///     total: 15,///     enabled: 14,///     builtin: 12,///     skill: 2,///     mcp: 0,///     a2a: 0,///     custom: 1,/// };////// stats.print();/// ```#[derive(Debug, Clone, Default)]pub struct ToolLoadStats {    /// 鎬诲伐鍏锋暟    pub total: usize,    /// 鍚敤鐨勫伐鍏锋暟    pub enabled: usize,    /// 鍐呯疆宸ュ叿鏁?    pub builtin: usize,    /// Skill 宸ュ叿鏁?    pub skill: usize,    /// MCP 宸ュ叿鏁?    pub mcp: usize,    /// A2A 宸ュ叿鏁?    pub a2a: usize,    /// 鑷畾涔夊伐鍏锋暟    pub custom: usize,}impl ToolLoadStats {    /// 鍒涘缓鏂扮殑绌虹粺璁?    pub fn new() -> Self {        Self::default()    }    /// 鎵撳嵃缁熻淇℃伅鍒版爣鍑嗚緭鍑?    ///    /// # 绀轰緥    ///    /// ```rust    /// use agentkit::runtime::loader::ToolLoadStats;    ///    /// let stats = ToolLoadStats {    ///     total: 15,    ///     enabled: 14,    ///     builtin: 12,    ///     skill: 2,    ///     mcp: 0,    ///     a2a: 0,    ///     custom: 1,    /// };    ///    /// stats.print();    /// // 杈撳嚭:    /// // Tool Loading Statistics:    /// //   Total:   15    /// //   Enabled: 14    /// //   By Source:    /// //     - BuiltIn: 12    /// //     - Skill:   2    /// //     - MCP:     0    /// //     - A2A:     0    /// //     - Custom:  1    /// ```    pub fn print(&self) {        println!("Tool Loading Statistics:");        println!("  Total:   {}", self.total);        println!("  Enabled: {}", self.enabled);        println!("  By Source:");        println!("    - BuiltIn: {}", self.builtin);        println!("    - Skill:   {}", self.skill);        println!("    - MCP:     {}", self.mcp);        println!("    - A2A:     {}", self.a2a);        println!("    - Custom:  {}", self.custom);    }}/// 渚挎嵎鐨勫伐鍏峰姞杞藉嚱鏁?////// 涓€閿姞杞藉唴缃伐鍏峰拰 Skills銆?////// # 鍙傛暟////// - `skill_dir`: Skills 鐩綍璺緞锛堝彲閫夛級/// - `include_builtin`: 鏄惁鍖呭惈鍐呯疆宸ュ叿////// # 杩斿洖鍊?////// 杩斿洖 `(ToolRegistry, ToolLoadStats)` 鍏冪粍銆?////// # 绀轰緥////// ```rust,no_run/// use agentkit::runtime::loader::load_all_tools;////// # async fn example() -> Result<(), Box<dyn std::error::Error + Send + Sync>> {/// let (registry, stats) = load_all_tools(///     Some("skills"),  // Skills 鐩綍///     true,            // 鍖呭惈鍐呯疆宸ュ叿/// ).await?;////// stats.print();/// # Ok(())/// # }/// ```pub async fn load_all_tools(    skill_dir: Option<impl AsRef<Path>>,    include_builtin: bool,) -> Result<(ToolRegistry, ToolLoadStats), Box<dyn std::error::Error + Send + Sync>> {    let mut loader = ToolLoader::new();    if include_builtin {        #[cfg(feature = "skills")]        {            loader = loader.load_builtin_tools();        }    }    if let Some(dir) = skill_dir {        loader = loader.load_skills_from_dir(dir).await?;    }    Ok(loader.build_with_stats())}
